1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	const RUNE_BLOCK_SIZE = 3;
13	const RUNE_BLOCK_PRICE = 60;
14	
15	interface Item {
16	  type: string;
17	}
18	
19	interface QuoteStep {
20	  op: "quote";
21	  items: Item[];
22	}
23	
24	interface Scenario {
25	  customer: { yearsWithMHPCO: number };
26	  steps: QuoteStep[];
27	}
28	
29	export function runScenario(input: unknown): unknown {
30	  const scenario = input as Scenario;
31	  const results = scenario.steps.map((step) => {
32	    const countsByType: Record<string, number> = {};
33	    for (const item of step.items) {
34	      countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
35	    }
36	    let basePremium = 0;
37	    for (const [type, count] of Object.entries(countsByType)) {
38	      if (type === "rune" && count === RUNE_BLOCK_SIZE) {
39	        basePremium += RUNE_BLOCK_PRICE;
40	      } else {
41	        const perItem = BASE_PREMIUM[type] ?? 0;
42	        basePremium += perItem * count;
43	      }
44	    }
45	    const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
46	    const rawPremium = basePremium + firstInsurance + PROCESSING_FEE;
47	    const premium = Math.ceil(rawPremium);
48	    return { premium };
49	  });
50	  return { results };
51	}
